# OEIS sequence: A356238

from sympy import bernoulli
def A356238(n):
    c, j = 0, 1
    while j <= n:
        k = n//j
        m = n//k
        c += k**n*(bernoulli(n+1,m+1)-bernoulli(n+1,j))
        j = m+1
    return c//(n+1) # _Chai Wah Wu_, May 14 2026

